#include<bits/stdc++.h>
using namespace std;
int a[100010],s[100010];
vector<int> v[100010];
int main()
{
    int n;
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        v[a[i]].push_back(i);
    }
    int B=sqrt(n*log2(n));
    for(int i=1;i<=n;i++)
    {
        if(v[i].size()>0)
        {
            for(int x=1;x<=B;x++)
            {
                int lst=-1e9,cnt=0;
                for(int j:v[i])
                {
                    if(j-lst>x)
                    {
                        cnt++;
                        lst=j;
                    }
                }
                s[x]+=cnt;
                s[x+1]-=cnt;
            }
            for(int x=B+1;x<=n;)
            {
                int lst=-1e9,cnt1=0;
                for(int j:v[i])
                {
                    if(j-lst>x)
                    {
                        cnt1++;
                        lst=j;
                    }
                }
                int best;
                int l=x,r=n;
                while(l<=r)
                {
                    int mid=(l+r)/2;
                    int lst=-1e9,cnt=0;
                    for(int j:v[i])
                    {
                        if(j-lst>mid)
                        {
                            cnt++;
                            lst=j;
                        }
                    }
                    if(cnt1==cnt)
                    {
                        l=mid+1;
                        best=mid;
                    }
                    else
                    {
                        r=mid-1;
                    }
                }
                s[x]+=cnt1;
                s[best+1]-=cnt1;
                x=best+1;
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        s[i]+=s[i-1];
        printf("%d\n",s[i]);
    }
    return 0;
}
